import{_ as p,C as i,o as n,c as A,a5 as e,b as r,w as a,a as o,E as l,a4 as E}from"./chunks/framework.sOZL8giL.js";const C=JSON.parse('{"title":"成本、自主与熵增","description":"","frontmatter":{},"headers":[],"relativePath":"01-Harness工程核心原则/03-成本、自主与熵增.md","filePath":"01-Harness工程核心原则/03-成本、自主与熵增.md","lastUpdated":1774181700000}'),g={name:"01-Harness工程核心原则/03-成本、自主与熵增.md"};function d(h,t,B,u,c,b){const s=i("Mermaid");return n(),A("div",null,[t[2]||(t[2]=e('<h1 id="成本、自主与熵增" tabindex="-1">成本、自主与熵增 <a class="header-anchor" href="#成本、自主与熵增" aria-label="Permalink to &quot;成本、自主与熵增&quot;">​</a></h1><p><strong>Harness Engineering 核心原则 · 第三章</strong></p><blockquote><p>代码变便宜了，等待变贵了。然后 Agent 接管了全流程，但熵增也随之而来。</p></blockquote><p>前两章我们建立了 Harness 的基础——工程师变成系统设计师，Agent 拥有了眼睛、地图和法律。现在我们要面对三个更深层的问题：成本结构怎么变了？自主的边界在哪里？大量自动生成的代码带来的熵增怎么办？</p><hr><h2 id="一、当等待成为最昂贵的成本" tabindex="-1">一、当等待成为最昂贵的成本 <a class="header-anchor" href="#一、当等待成为最昂贵的成本" aria-label="Permalink to &quot;一、当等待成为最昂贵的成本&quot;">​</a></h2><p>传统的软件工程有一套大家都很熟悉的流程：写完代码 → 开 PR → 等人 Review → 测试全过 → 审批通过 → 才能合并。每一步都是一道门。</p><p>对人类团队来说，这很合理——人写代码慢，每次合并都是一件大事儿，值得停下来仔细检查。</p><p>但当 Agent 接管了代码生产，这套传统逻辑可能适得其反。</p><h3 id="成本函数反转" tabindex="-1">成本函数反转 <a class="header-anchor" href="#成本函数反转" aria-label="Permalink to &quot;成本函数反转&quot;">​</a></h3><p>想象一个工厂的质检流程。传统场景每小时生产 10 件，质检员在每件出厂前仔细检查——完全合理。但当产量飙升到每小时 1000 件，质检员根本看不过来。<strong>整条线都会被他一个人堵死。</strong></p><p>而这时候，修一件次品的成本几乎为零——自动返工几秒钟就能修好。</p><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">传统世界</th><th style="text-align:left;">Agent 世界</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>修正成本</strong></td><td style="text-align:left;">很贵</td><td style="text-align:left;">很便宜</td></tr><tr><td style="text-align:left;"><strong>等待成本</strong></td><td style="text-align:left;">很便宜</td><td style="text-align:left;"><strong>最贵</strong></td></tr></tbody></table><p>传统世界的逻辑是&quot;修正贵，等待便宜&quot;→ 多检查、多审批，宁可慢也不能错。Agent 世界的逻辑是&quot;修正便宜，等待最贵&quot;→ <strong>快速放行，快速暴露问题，快速修正。</strong></p>',14)),(n(),r(E,null,{default:a(()=>[l(s,{id:"mermaid-78",class:"mermaid",graph:"quadrantChart%0A%20%20%20%20title%20%E6%88%90%E6%9C%AC%E5%87%BD%E6%95%B0%E5%8F%8D%E8%BD%AC%0A%20%20%20%20x-axis%20%22%E7%AD%89%E5%BE%85%E6%88%90%E6%9C%AC%E4%BD%8E%22%20--%3E%20%22%E7%AD%89%E5%BE%85%E6%88%90%E6%9C%AC%E9%AB%98%22%0A%20%20%20%20y-axis%20%22%E4%BF%AE%E6%AD%A3%E6%88%90%E6%9C%AC%E4%BD%8E%22%20--%3E%20%22%E4%BF%AE%E6%AD%A3%E6%88%90%E6%9C%AC%E9%AB%98%22%0A%20%20%20%20quadrant-1%20%22%E4%BC%A0%E7%BB%9F%E4%B8%96%E7%95%8C%22%0A%20%20%20%20quadrant-2%20%22%E6%9C%80%E5%B7%AE%E6%83%85%E5%86%B5%22%0A%20%20%20%20quadrant-3%20%22Agent%20%E7%90%86%E6%83%B3%E5%8C%BA%22%0A%20%20%20%20quadrant-4%20%22%E9%AB%98%E9%A3%8E%E9%99%A9%22%0A%20%20%20%20%22%E4%BC%A0%E7%BB%9F%E5%BC%80%E5%8F%91%22%3A%20%5B0.2%2C%200.8%5D%0A%20%20%20%20%22Agent%20%E5%BC%80%E5%8F%91%22%3A%20%5B0.85%2C%200.15%5D%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[o(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=e(`<blockquote><p>💡 <strong>图解：</strong> 传统开发在&quot;修正贵、等待便宜&quot;象限，Agent 开发反转到&quot;修正便宜、等待最贵&quot;——工程实践必须随之反转。</p></blockquote><h3 id="三个具体动作" tabindex="-1">三个具体动作 <a class="header-anchor" href="#三个具体动作" aria-label="Permalink to &quot;三个具体动作&quot;">​</a></h3><p><strong>最小化阻塞门控。</strong> 不是不要检查，而是把&quot;必须等人批准才能继续&quot;变成&quot;自动检查 + 快速反馈&quot;，把&quot;层层审批&quot;变成&quot;护栏 + 自动修复&quot;。</p><p><strong>PR 保持短生命周期。</strong> 人类往往习惯花好几天写一个极其庞大的 PR，导致漫长的 Review 和极高的合并冲突率。Agent 流程的做法是高频小步快跑——合并碰壁的概率极低，哪怕出错了，代替一个短周期的修复 PR 也就是几秒钟的事儿。</p><p><strong>绝不让 Flaky Test 无限期阻塞进度。</strong> 那种跑同一段代码有时候通有时候挂的幽灵测试，在传统做法中会阻塞所有人、停机排查。在 Agent 时代，用后续的重跑机制来解决——绝不无限期地卡住全盘进度，因为等待的代价太高昂了。</p><blockquote><p><strong>最佳工程实践不是绝对的，它取决于你的约束条件。</strong> 当约束条件发生数量级变化时，最佳实践本身也必须跟着变。</p></blockquote><hr><h2 id="二、端到端自主-agent-接管全流程" tabindex="-1">二、端到端自主：Agent 接管全流程 <a class="header-anchor" href="#二、端到端自主-agent-接管全流程" aria-label="Permalink to &quot;二、端到端自主：Agent 接管全流程&quot;">​</a></h2><p>一旦跨越了某个工程临界点，Agent 将完全接管从代码到运维的每一环。</p><h3 id="agent-生成的不只是代码" tabindex="-1">Agent 生成的不只是代码 <a class="header-anchor" href="#agent-生成的不只是代码" aria-label="Permalink to &quot;Agent 生成的不只是代码&quot;">​</a></h3><p>当 OpenAI 说这个代码库是由 Codex 生成时，指的不只是产品代码和测试代码。Agent 生成的清单包括：CI 配置与发布工具链、内部开发管理工具、架构设计的历史文档、评估系统与测试框架、PR 下的审查评论与回复、仓库本身的脚本、生产环境的监控面板定义文件。</p><p>Agent 正在像人类一样直接使用标准的开发工具——拉取审查意见、进行内联回复、推送更新、自己压缩并合并 PR。</p><h3 id="人类工程师在干什么" tabindex="-1">人类工程师在干什么？ <a class="header-anchor" href="#人类工程师在干什么" aria-label="Permalink to &quot;人类工程师在干什么？&quot;">​</a></h3><p>当繁琐的执行环节被全面接管，人类的工作重心转移到了一个完全不同的抽象层：</p><ol><li><strong>排定优先级</strong>——决定做什么，不做什么</li><li><strong>翻译需求</strong>——将用户反馈翻译成明确的验收标准</li><li><strong>最终验证</strong>——验证交付成果是否符合预期</li></ol><p>如果在中间过程中 Agent 卡壳了，人类也<strong>绝对不会下场去帮他逐行修代码</strong>。他们会把 Agent 的挣扎视为一种报错信号，去排查：是不是系统里少了某个检测工具？缺了某种护栏？还是文档没写清楚？找到缺口并补充到系统后，依旧让 Agent 自己去完成代码修复。</p><blockquote><p><strong>人类不再是执行者，而是环境与标准的设计者。</strong></p></blockquote><h3 id="全自动闭环" tabindex="-1">全自动闭环 <a class="header-anchor" href="#全自动闭环" aria-label="Permalink to &quot;全自动闭环&quot;">​</a></h3><p>随着测试、评审、反馈、处理等整个开发循环都被明确编码到系统架构中后，Agent 跨越了一个决定性的自治阈值：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入需求 → 查验代码库现状 → 遇到 Bug 自主复现</span></span>
<span class="line"><span>→ 录制展示错误的视频（留作证据）→ 完成代码修复</span></span>
<span class="line"><span>→ 再次驱动应用进行自我验证 → 录制成功运行的视频</span></span>
<span class="line"><span>→ 自己开启 PR → 响应审查意见</span></span>
<span class="line"><span>→ 遇到构建报错自我排查并修复</span></span>
<span class="line"><span>→ [涉及方向性抉择？] → 按铃叫人类</span></span>
<span class="line"><span>→ 否则自动合并代码</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>除非遇到真正涉及方向性抉择的情况，它才会按铃叫人类。否则它会一路走到底，最终自动合并代码。</p><p>从输入一段需求到最终代码合并，中间长达数小时的执行过程全由机器接管。</p><h3 id="冷峻的提醒" tabindex="-1">冷峻的提醒 <a class="header-anchor" href="#冷峻的提醒" aria-label="Permalink to &quot;冷峻的提醒&quot;">​</a></h3><p>但 OpenAI 紧接着给出了一个非常冷峻的提醒：此行为高度依赖于该代码库的具体结构和工具链，也不应假设其能普遍推广——除非投入了类似的开发资源。</p><p>这种自治<strong>不能被简单复制粘贴</strong>。让大模型自动写代码而不搭建基础设施，只会制造出加速系统崩溃的数字垃圾。</p><blockquote><p><strong>越是高度的自治，越离不开极度严密的环境设计与工程约束。</strong></p></blockquote><hr><h2 id="三、对抗熵增-技术债的自动偿还" tabindex="-1">三、对抗熵增：技术债的自动偿还 <a class="header-anchor" href="#三、对抗熵增-技术债的自动偿还" aria-label="Permalink to &quot;三、对抗熵增：技术债的自动偿还&quot;">​</a></h2><p>当 Agent 能瞬间写出大量代码，随之而来的是逐渐难以察觉却不断累积的<strong>代码熵增</strong>。</p><h3 id="agent-的本能-复制与放大" tabindex="-1">Agent 的本能：复制与放大 <a class="header-anchor" href="#agent-的本能-复制与放大" aria-label="Permalink to &quot;Agent 的本能：复制与放大&quot;">​</a></h3><p>哪怕你投入了再多精力去设计架构护栏，Agent 的本能依然是<strong>复制</strong>——它会模仿仓库中已有代码的模式。一旦某个角落出现了细微的技术债，这种便宜的妥协就可能被 Agent 快速复制放大，最终导致系统结构逐渐失去连贯性。</p><p>恶性循环：技术债 → Agent 复制 → 更多技术债 → 更快复制 → 系统失控。</p><h3 id="人工清理为什么失败" tabindex="-1">人工清理为什么失败 <a class="header-anchor" href="#人工清理为什么失败" aria-label="Permalink to &quot;人工清理为什么失败&quot;">​</a></h3><p>OpenAI 团队曾尝试每周抽出大约 20% 的时间，由工程师专门做代码清理。听起来合理，但在一个高度自动化、吞吐量极高的环境中，代码生成的速度远超人类清理的速度。人工清理永远追不上自动生产。</p><h3 id="三层防御体系" tabindex="-1">三层防御体系 <a class="header-anchor" href="#三层防御体系" aria-label="Permalink to &quot;三层防御体系&quot;">​</a></h3>`,35)),(n(),r(E,null,{default:a(()=>[l(s,{id:"mermaid-200",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E4%BB%A3%E7%A0%81%E7%86%B5%E5%A2%9E%5D%20--%3E%20B%5B%E7%AC%AC%E4%B8%80%E5%B1%82%3A%20%E9%BB%84%E9%87%91%E5%8E%9F%E5%88%99%5D%0A%20%20%20%20B%20--%3E%7CLinter%20%E6%9C%BA%E6%A2%B0%E6%89%A7%E8%A1%8C%7C%20C%5B%E7%AB%8B%E5%8D%B3%E6%8B%A6%E6%88%AA%E8%BF%9D%E8%A7%84%5D%0A%20%20%20%20C%20--%3E%20D%5B%E7%AC%AC%E4%BA%8C%E5%B1%82%3A%20%E6%8C%81%E7%BB%AD%E6%B8%85%E7%90%86%20Agent%5D%0A%20%20%20%20D%20--%3E%7C%E5%90%8E%E5%8F%B0%E5%AE%9A%E6%9C%9F%E6%89%AB%E6%8F%8F%7C%20E%5B%E8%87%AA%E5%8A%A8%E7%94%9F%E6%88%90%E9%87%8D%E6%9E%84%20PR%5D%0A%20%20%20%20E%20--%3E%20F%5B%E7%AC%AC%E4%B8%89%E5%B1%82%3A%20%E8%87%AA%E5%8A%A8%E5%81%BF%E8%BF%98%E6%9C%BA%E5%88%B6%5D%0A%20%20%20%20F%20--%3E%7C%E5%83%8F%E7%B3%BB%E7%BB%9F%E5%9E%83%E5%9C%BE%E5%9B%9E%E6%94%B6%7C%20G%5B%E6%8C%81%E7%BB%AD%E5%B0%8F%E6%AD%A5%E6%B8%85%E7%90%86%E7%BB%93%E6%9E%84%E5%81%8F%E7%A7%BB%5D%0A%20%20%20%20A%20-.-%3E%7C%E8%8B%A5%E8%B7%B3%E8%BF%87%E9%98%B2%E5%BE%A1%7C%20H%5B%E6%8A%80%E6%9C%AF%E5%80%BA%E6%8C%87%E6%95%B0%E7%BA%A7%E5%A2%9E%E9%95%BF%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[o(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=e('<blockquote><p>💡 <strong>图解：</strong> 三层防御像持续运行的垃圾回收——不等系统失控才大规模重构，而是小步自动清理。</p></blockquote><p><strong>第一层：黄金原则。</strong> 把工程师对代码的品味编码成一组明确的规则——可以被机器检查和强制执行。比如：优先使用共享的工具库而不是在不同模块里各自手写小工具函数；拿到外部数据后必须先做显式的结构验证，不能直接假设字段一定存在。</p><p><strong>第二层：持续运行的清理机制。</strong> 后台定期运行专门的 Agent 任务，扫描代码库中是否出现偏离黄金原则的模式。一旦发现问题，自动生成针对性的重构 PR。这些 PR 力度很小，可以快速 Review 甚至自动合并。</p><p>这种机制更像系统底层的<strong>垃圾回收</strong>——不是等系统失控再进行一次痛苦的大规模重构，而是持续小步、自动地清理结构偏移。</p><p><strong>第三层：技术债的自动偿还。</strong> 在 Agent 时代，技术债更像是<strong>高利贷</strong>——如果放任它，累积增长速度会超过你的偿还能力。唯一可持续的方式是建立一个持续小额自动偿还的机制。</p><hr><h2 id="四、纪律的转移" tabindex="-1">四、纪律的转移 <a class="header-anchor" href="#四、纪律的转移" aria-label="Permalink to &quot;四、纪律的转移&quot;">​</a></h2><p>在这些实践背后，有一件事非常明确：</p><blockquote><p><strong>纪律正在从代码本身转移到工程的支架上。</strong></p></blockquote><p>代码本身将不再是纪律的主要载体。支架指的是工具、执行环境、系统抽象、反馈回路——整个底层的控制系统。</p><p>现在最困难的挑战不在于如何榨取模型生成代码的能力极限，而在于<strong>你能否构建出一个足够稳健的控制架构</strong>。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ol><li><strong>成本反转</strong>——修正变便宜、等待变贵；最小化阻塞门控，高频小步快跑</li><li><strong>端到端自主</strong>——Agent 接管从代码到运维的全流程，人类变成甲方工程师</li><li><strong>自治的代价</strong>——高度自治需要极高的基础设施门槛，不是撒手不管</li><li><strong>熵增对抗</strong>——黄金原则 + 持续清理 Agent + 自动偿还机制</li><li><strong>纪律转移</strong>——从代码本身转移到工程支架（工具、环境、反馈回路）</li></ol><hr><p><a href="./02-让Agent拥有感官.html">← 上一章：让 Agent 拥有感官</a> | <a href="./04-Harness即操作系统.html">下一章：Harness 即操作系统 →</a></p>',16))])}const _=p(g,[["render",d]]);export{C as __pageData,_ as default};
